export const convertPropsToClasses = ({ color, size, variant, }) => {
    let classes = '';
    if (color) {
        classes = `${classes} modus-wc-text-${color}`;
    }
    if (size) {
        classes = `${classes} modus-wc-loader-${size}`;
    }
    if (variant) {
        classes = `${classes} modus-wc-loader-${variant}`;
    }
    return classes.trim();
};
